// WRONG — s[k] in always_comb creates a combinational loop
// always_comb begin
//   s[0] = data_in * coeff[0];
//   s[1] = s[0] + data_in * coeff[1];
// end

// RIGHT — s[k] must be registered
always_ff @(posedge clk or negedge rst_n) begin
  if (!rst_n) begin
    for (int i = 0; i < TAPS; i++) s[i] <= '0;
  end else if (valid_in) begin
    s[TAPS-1] <= data_in * coeff[TAPS-1];
    for (int i = TAPS-2; i >= 0; i--)
      s[i] <= s[i+1] + data_in * coeff[i];
  end
end
